import os# Планы:# Сделать удобный менеджер для выбора файлов, в идеале, чтобы сделать в контекстном менеджере# Windows вкладку для отправки через наш скрипт# Что такое cheksum:# https://www.geeksforgeeks.org/computer-networks/error-detection-in-computer-networks/def choose_file():    print('received_files:')    files = os.listdir('received_files')    for num,file in enumerate(os.listdir('received_files')):        print('-',num,'-',file)    target_file = files[int(input('Введите номер файла для отправки: '))]    print(f'Выбран файл: {target_file}')    file_info = {'name': target_file, 'size': os.path.getsize('received_files/'+target_file), 'checksum': "Тут ебля"}    # size = os.path.getsize('received_files/'+target_file)    # print(size/2)choose_file()